{
  "integrative": {
    "title": "Integrative Close: Workshop Circuit Design",
    "objective": "Synthesize the selection of a specific protective device type and rating with the calculation of minimum tabulated current-carrying capacity (It) for a real-world installation scenario.",
    "retrievalTextLines": [
      "Scenario: You are designing a circuit for a workshop machine with a design current (Ib) of 26A. The machine has a high starting current (inrush).",
      "Installation Conditions: The cable is installed in an area with an ambient temperature of 40°C (Ca = 0.87) and is grouped with two other circuits (Cg = 0.70).",
      "Protective Device: A BS EN 60898 circuit breaker must be used. Standard ratings available: 20A, 25A, 32A, 40A, 50A."
    ],
    "questionText": "Identify the most appropriate Type (B, C, or D) and nominal rating (In) for the circuit breaker, then calculate the minimum required tabulated current-carrying capacity (It) for the cable. Show your calculation and round the final It value to two decimal places.",
    "answerGuidance": [
      "Type C",
      "In = 32A",
      "It = 52.55A",
      "32 / (0.87 x 0.70) = 52.55",
      "Type C, 32A breaker, 52.55A"
    ],
    "hint": "First, choose Type C for the high starting current. Select a 32A breaker because it is the next standard size above the 26A load. Finally, use the formula It ≥ In / (Ca x Cg) to find the cable capacity."
  }
}

